import { motion } from 'framer-motion'

import { WelcomeBanner } from '../components/dashboard/welcome-banner'
import { StatsSection } from '../components/dashboard/stats-card'
import { AnalyticsSection } from '../components/dashboard/analytics-charts'
import { SmartSuggestions, ImpactSection } from '../components/dashboard/smart-suggestions'
import { ActivityFeed, NGORequestsPanel } from '../components/dashboard/activity-feed'

export default function DonorDashboard() {
  return (
    <div className="w-full bg-white min-h-screen pb-20">
      {/* Premium Food Hero Section */}
      <div 
        className="h-[400px] rounded-b-[4rem] mb-12 relative overflow-hidden shadow-2xl"
        style={{
          backgroundImage: 'url(/bg-landing.png)',
          backgroundSize: 'cover',
          backgroundPosition: 'center',
        }}
      >
        <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent" />
        <div className="absolute inset-0 bg-emerald-900/10" />
        
        <div className="absolute inset-0 flex items-end justify-center pb-16">
          <div className="text-center text-white px-6">
            <motion.h2 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              className="text-6xl font-black mb-4 tracking-tight"
            >
              Colorful Impact, <span className="text-primary">Real Change</span>
            </motion.h2>
            <motion.p 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.1 }}
              className="text-xl text-white/90 font-medium max-w-2xl mx-auto"
            >
              Join thousands rescuing food and feeding communities. Every meal saved is a life touched.
            </motion.p>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-6 lg:px-12">
        {/* Welcome Banner */}
        <div className="mb-12">
          <WelcomeBanner />
        </div>

        {/* Stats Section */}
        <div className="mb-16">
          <StatsSection />
        </div>

        {/* Analytics Charts */}
        <div className="mb-16 bg-gray-50/50 p-10 rounded-[3rem] border border-gray-100">
          <h3 className="text-2xl font-black text-gray-900 mb-8 uppercase tracking-widest text-center">Impact Analytics</h3>
          <AnalyticsSection />
        </div>

        {/* Smart Suggestions */}
        <div className="mb-16">
          <SmartSuggestions />
        </div>

        {/* Activity & Requests Section */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-10 mb-16">
          <div className="lg:col-span-1">
            <ActivityFeed />
          </div>
          <div className="lg:col-span-2">
            <NGORequestsPanel />
          </div>
        </div>

        {/* Impact Section */}
        <div className="rounded-[3rem] overflow-hidden shadow-xl shadow-emerald-900/5">
          <ImpactSection />
        </div>
      </div>
    </div>
  )
}
