'use client'

import { motion } from 'framer-motion'
import { Bell, Settings, User } from 'lucide-react'

export function DashboardNavbar() {
  return (
    <motion.nav
      className="fixed top-0 right-0 left-0 lg:left-64 h-20 glass border-b border-white/10 z-20 px-6 lg:px-12"
      initial={{ opacity: 1, y: 0 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.4 }}
    >
      <div className="h-full flex items-center justify-between">
        <div>
          <p className="text-sm text-muted-foreground">Welcome back</p>
          <h2 className="text-lg font-semibold text-foreground">Rajesh's Restaurant</h2>
        </div>

        <div className="flex items-center gap-4">
          {/* Notification Icon */}
          <motion.button
            className="relative p-2 rounded-lg hover:bg-primary/10 transition-colors"
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            <Bell size={20} className="text-muted-foreground hover:text-primary" />
            <span className="absolute top-1 right-1 w-2 h-2 bg-destructive rounded-full" />
          </motion.button>

          {/* Settings Icon */}
          <motion.button
            className="p-2 rounded-lg hover:bg-primary/10 transition-colors"
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            <Settings size={20} className="text-muted-foreground hover:text-primary" />
          </motion.button>

          {/* User Profile */}
          <motion.div
            className="flex items-center gap-3 ml-4 pl-4 border-l border-white/10"
            whileHover={{ scale: 1.02 }}
          >
            <div className="w-10 h-10 rounded-full bg-gradient-to-br from-emerald-500 to-teal-600 flex items-center justify-center text-white font-semibold">
              RR
            </div>
            <div className="hidden sm:block">
              <p className="text-sm font-medium text-foreground">Rajesh</p>
              <p className="text-xs text-muted-foreground">Premium Member</p>
            </div>
          </motion.div>
        </div>
      </div>
    </motion.nav>
  )
}
