'use client'

import { motion } from 'framer-motion'
import { ArrowRight, Calendar } from 'lucide-react'

export function WelcomeBanner() {
  const now = new Date()
  const greeting =
    now.getHours() < 12
      ? 'Good morning'
      : now.getHours() < 18
        ? 'Good afternoon'
        : 'Good evening'

  return (
    <motion.div
      className="p-8 rounded-2xl border border-white/10 mb-8 relative overflow-hidden"
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.4 }}
      style={{
        backgroundImage: 'url(/food-background.jpg)',
        backgroundSize: 'cover',
        backgroundPosition: 'center',
      }}
    >
      {/* Dark overlay for text readability */}
      <div className="absolute inset-0 bg-black/40 backdrop-blur-sm rounded-2xl" />
      
      {/* Decorative gradient overlay */}
      <div className="absolute inset-0 bg-gradient-to-r from-emerald-900/40 to-teal-900/40 rounded-2xl" />

      <div className="relative z-10">
        <div className="flex items-start justify-between mb-4">
          <div>
            <p className="text-sm text-muted-foreground">{greeting},</p>
            <h1 className="text-4xl font-bold text-foreground mt-2">
              Rajesh&apos;s Restaurant
            </h1>
            <p className="text-base text-muted-foreground mt-2">
              Thank you for being part of the food rescue community. Let&apos;s make an impact together today!
            </p>
          </div>
          <div className="text-right">
            <div className="flex items-center gap-2 justify-end text-sm text-muted-foreground mb-2">
              <Calendar size={16} />
              <span>{now.toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' })}</span>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mt-6">
          <motion.button
            className="flex items-center justify-center gap-2 px-6 py-3 bg-gradient-to-r from-emerald-500 to-teal-600 text-white rounded-lg font-semibold hover:shadow-lg transition-shadow"
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            Post Food Now
            <ArrowRight size={18} />
          </motion.button>
          <motion.button
            className="flex items-center justify-center gap-2 px-6 py-3 bg-white/10 border border-white/20 text-foreground rounded-lg font-semibold hover:bg-white/15 transition-colors"
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            Schedule Pickup
          </motion.button>
          <motion.button
            className="flex items-center justify-center gap-2 px-6 py-3 bg-white/10 border border-white/20 text-foreground rounded-lg font-semibold hover:bg-white/15 transition-colors"
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            View Guidelines
          </motion.button>
        </div>
      </div>
    </motion.div>
  )
}
