'use client'

import { motion } from 'framer-motion'
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  PieChart,
  Pie,
  Cell,
} from 'recharts'

const weeklyData = [
  { day: 'Mon', donations: 45 },
  { day: 'Tue', donations: 52 },
  { day: 'Wed', donations: 48 },
  { day: 'Thu', donations: 61 },
  { day: 'Fri', donations: 55 },
  { day: 'Sat', donations: 67 },
  { day: 'Sun', donations: 58 },
]

const categoryData = [
  { name: 'Vegetables', value: 35, color: '#10b981' },
  { name: 'Bakery', value: 25, color: '#f59e0b' },
  { name: 'Dairy', value: 20, color: '#3b82f6' },
  { name: 'Prepared Food', value: 20, color: '#8b5cf6' },
]

export function AnalyticsSection() {
  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
      {/* Weekly Donations Chart */}
      <motion.div
        className="glass p-6 rounded-2xl border border-white/10 lg:col-span-2"
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.4, duration: 0.4 }}
        whileHover={{ scale: 1.01 }}
      >
        <h3 className="text-lg font-semibold text-foreground mb-4">
          Weekly Donations
        </h3>
        <ResponsiveContainer width="100%" height={300}>
          <LineChart data={weeklyData}>
            <defs>
              <linearGradient id="colorDonations" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#10b981" stopOpacity={0.8} />
                <stop offset="95%" stopColor="#10b981" stopOpacity={0} />
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.1)" />
            <XAxis stroke="rgba(255,255,255,0.5)" />
            <YAxis stroke="rgba(255,255,255,0.5)" />
            <Tooltip
              contentStyle={{
                backgroundColor: 'rgba(20, 20, 35, 0.9)',
                border: '1px solid rgba(255,255,255,0.1)',
                borderRadius: '8px',
              }}
              labelStyle={{ color: '#fff' }}
            />
            <Line
              type="monotone"
              dataKey="donations"
              stroke="#10b981"
              strokeWidth={3}
              dot={{ fill: '#10b981', r: 5 }}
              activeDot={{ r: 7 }}
              fillOpacity={1}
              fill="url(#colorDonations)"
            />
          </LineChart>
        </ResponsiveContainer>
      </motion.div>

      {/* Food Categories Pie Chart */}
      <motion.div
        className="glass p-6 rounded-2xl border border-white/10"
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.5, duration: 0.4 }}
        whileHover={{ scale: 1.01 }}
      >
        <h3 className="text-lg font-semibold text-foreground mb-4">
          Food Categories
        </h3>
        <ResponsiveContainer width="100%" height={300}>
          <PieChart>
            <Pie
              data={categoryData}
              cx="50%"
              cy="50%"
              innerRadius={60}
              outerRadius={100}
              paddingAngle={5}
              dataKey="value"
            >
              {categoryData.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={entry.color} />
              ))}
            </Pie>
            <Tooltip
              contentStyle={{
                backgroundColor: 'rgba(20, 20, 35, 0.9)',
                border: '1px solid rgba(255,255,255,0.1)',
                borderRadius: '8px',
              }}
              labelStyle={{ color: '#fff' }}
            />
          </PieChart>
        </ResponsiveContainer>
        <div className="mt-4 space-y-2">
          {categoryData.map((category) => (
            <div key={category.name} className="flex items-center justify-between text-sm">
              <div className="flex items-center gap-2">
                <div className="w-3 h-3 rounded-full" style={{ backgroundColor: category.color }} />
                <span className="text-muted-foreground">{category.name}</span>
              </div>
              <span className="font-semibold text-foreground">{category.value}%</span>
            </div>
          ))}
        </div>
      </motion.div>
    </div>
  )
}
