'use client'

import { motion } from 'framer-motion'
import { Lightbulb, Zap, TrendingUp, Award, Leaf, Users } from 'lucide-react'

const suggestionsData = [
  {
    icon: Zap,
    title: 'High-Demand Foods',
    description:
      'NGOs are requesting fresh vegetables. You have surplus from today&apos;s inventory.',
    action: 'View Match',
    color: 'from-emerald-500/20 to-teal-500/20',
  },
  {
    icon: TrendingUp,
    title: 'Donation Streak',
    description:
      'You&apos;re on a 14-day streak! Reach 30 days for a community badge.',
    action: 'View Badges',
    color: 'from-purple-500/20 to-pink-500/20',
  },
  {
    icon: Award,
    title: 'Partner Rewards',
    description:
      'Earn loyalty points with every donation. Redeem for tax benefits.',
    action: 'See Benefits',
    color: 'from-orange-500/20 to-red-500/20',
  },
]

export function SmartSuggestions() {
  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
      {suggestionsData.map((suggestion, index) => {
        const Icon = suggestion.icon
        return (
          <motion.div
            key={suggestion.title}
            className={`glass p-6 rounded-2xl border border-white/10 bg-gradient-to-br ${suggestion.color}`}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.8 + index * 0.05 }}
            whileHover={{ scale: 1.02 }}
          >
            <div className="flex items-start gap-4">
              <div className="p-3 rounded-lg bg-white/10">
                <Icon size={20} className="text-primary" />
              </div>
              <div className="flex-1">
                <h4 className="text-sm font-semibold text-foreground mb-1">
                  {suggestion.title}
                </h4>
                <p className="text-xs text-muted-foreground mb-4">
                  {suggestion.description}
                </p>
                <motion.button
                  className="text-xs font-semibold text-primary hover:text-primary/80 transition-colors"
                  whileHover={{ x: 2 }}
                >
                  {suggestion.action} →
                </motion.button>
              </div>
            </div>
          </motion.div>
        )
      })}
    </div>
  )
}

export function ImpactSection() {
  return (
    <motion.div
      className="glass p-8 rounded-2xl border border-white/10 bg-gradient-to-r from-emerald-500/10 to-teal-500/10"
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: 0.95, duration: 0.4 }}
    >
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        {/* Impact Stats */}
        <div className="flex items-center gap-4">
          <div className="p-4 rounded-2xl bg-emerald-500/20">
            <Leaf size={32} className="text-emerald-500" />
          </div>
          <div>
            <p className="text-sm text-muted-foreground">Total Impact</p>
            <p className="text-3xl font-bold text-foreground">2,840 kg</p>
            <p className="text-xs text-emerald-500 mt-1">Food saved from waste</p>
          </div>
        </div>

        {/* Lives Helped */}
        <div className="flex items-center gap-4">
          <div className="p-4 rounded-2xl bg-blue-500/20">
            <Users size={32} className="text-blue-500" />
          </div>
          <div>
            <p className="text-sm text-muted-foreground">Lives Impacted</p>
            <p className="text-3xl font-bold text-foreground">3,420+</p>
            <p className="text-xs text-blue-500 mt-1">People helped so far</p>
          </div>
        </div>

        {/* CO2 Saved */}
        <div className="flex items-center gap-4">
          <div className="p-4 rounded-2xl bg-green-500/20">
            <TrendingUp size={32} className="text-green-500" />
          </div>
          <div>
            <p className="text-sm text-muted-foreground">Carbon Offset</p>
            <p className="text-3xl font-bold text-foreground">2.84 t CO₂</p>
            <p className="text-xs text-green-500 mt-1">Equivalent to 1 tree/year</p>
          </div>
        </div>
      </div>

      {/* Motivational Message */}
      <div className="mt-8 pt-8 border-t border-white/10">
        <p className="text-sm text-muted-foreground mb-3">
          Your Impact This Month
        </p>
        <div className="flex items-center justify-between">
          <div>
            <h4 className="text-lg font-semibold text-foreground mb-2">
              You&apos;re Making a Difference!
            </h4>
            <p className="text-sm text-muted-foreground max-w-md">
              Your donations have helped {Math.floor(Math.random() * 500 + 200)} people this month. Keep up the amazing work and help us build a more sustainable community.
            </p>
          </div>
          <motion.button
            className="px-6 py-3 bg-gradient-to-r from-emerald-500 to-teal-600 text-white rounded-lg font-semibold whitespace-nowrap ml-4"
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            Share Impact
          </motion.button>
        </div>
      </div>
    </motion.div>
  )
}
